// // This module implements a 2-to-1 multiplexer where the output Y is selected based on the inverse of the select signal S.
module top_module(
    input A,
    input B,
    input S,
    output reg Y
);always @ (A, B, S)
begin
    if (S == 0)
        Y = A;
    else
        Y = B;
end

endmodule
